import{_ as a,o as n,c as o,a0 as e}from"./chunks/framework.DV6pVIgV.js";const c=JSON.parse('{"title":"走向全球","description":"","frontmatter":{},"headers":[],"relativePath":"clf-c02/7.md","filePath":"clf-c02/7.md","lastUpdated":1783683776000}'),r={name:"clf-c02/7.md"};function s(d,t,i,l,g,p){return n(),o("div",null,[...t[0]||(t[0]=[e(`<h1 id="走向全球" tabindex="-1">走向全球 <a class="header-anchor" href="#走向全球" aria-label="Permalink to &quot;走向全球&quot;">​</a></h1><p>選擇 Region、全球基礎設施深入與基礎設施自動化。第一章介紹過 Region / AZ / Edge 的基本概念，這章深入——加上第一章沒講的「多 AZ 高可用 vs 多 Region 災難復原」，以及如何用自動化做一致的全球部署。</p><h2 id="先備知識" tabindex="-1">先備知識 <a class="header-anchor" href="#先備知識" aria-label="Permalink to &quot;先備知識&quot;">​</a></h2><ul><li><p><strong>CDN（內容傳遞網路）</strong></p><ul><li><a href="https://www.twister5.com.tw/post/whatiscdn/" target="_blank" rel="noreferrer">什麼是 CDN？</a></li><li><a href="https://www.cloudflare.com/learning/cdn/what-is-a-cdn/" target="_blank" rel="noreferrer">What is a CDN?（Cloudflare）</a></li></ul></li><li><p><strong>YAML</strong></p><ul><li><a href="https://www.redhat.com/en/topics/automation/what-is-yaml" target="_blank" rel="noreferrer">什麼是 YAML？（Red Hat）</a></li><li><a href="https://eandev.com/post/software/series/build-automated-deploy/yaml/" target="_blank" rel="noreferrer">淺談YAML 格式- 伊恩的開發狂想</a></li></ul></li></ul><h2 id="為什麼要走向全球" tabindex="-1">為什麼要走向全球 <a class="header-anchor" href="#為什麼要走向全球" aria-label="Permalink to &quot;為什麼要走向全球&quot;">​</a></h2><p>把應用程式部署到全球多個地點，主要解決四件事：</p><ol><li><strong>貼近使用者、降低延遲</strong> — 各地使用者連到最近的據點，反應更快</li><li><strong>符合法規</strong> — 某些資料依法必須留在特定國家 / 地區</li><li><strong>提高可靠性</strong> — 把服務分散到多個獨立地點，一處出事不會全倒</li><li><strong>擴大觸及</strong> — 幾分鐘就能在新地區開設據點，服務當地市場</li></ol><h2 id="選擇-aws-region-的四個考量" tabindex="-1">選擇 AWS Region 的四個考量 <a class="header-anchor" href="#選擇-aws-region-的四個考量" aria-label="Permalink to &quot;選擇 AWS Region 的四個考量&quot;">​</a></h2><p>把服務部署在哪個 Region，要綜合四個因素：</p><table tabindex="0"><thead><tr><th>考量</th><th>說明</th><th>什麼時候是決定性因素</th></tr></thead><tbody><tr><td><strong>法規與資料落地（Compliance）</strong></td><td>法規要求資料存放在特定國家 / 地區</td><td>「資料依法必須留在某國」→ 直接決定 Region</td></tr><tr><td><strong>鄰近使用者（Proximity）</strong></td><td>離主要使用者愈近，延遲愈低</td><td>「使用者集中在某地、要最低延遲」</td></tr><tr><td><strong>服務可用性（Feature availability）</strong></td><td>新服務不是每個 Region 都立刻有</td><td>「要用某個較新服務」→ 先確認該 Region 有沒有</td></tr><tr><td><strong>定價（Pricing）</strong></td><td>各 Region 價格不同</td><td>「在符合前述條件下，挑最便宜的」</td></tr></tbody></table><h2 id="aws-全球基礎設施" tabindex="-1">AWS 全球基礎設施 <a class="header-anchor" href="#aws-全球基礎設施" aria-label="Permalink to &quot;AWS 全球基礎設施&quot;">​</a></h2><h3 id="region-區域" tabindex="-1">Region（區域） <a class="header-anchor" href="#region-區域" aria-label="Permalink to &quot;Region（區域）&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Region（區域，如 ap-northeast-1 東京）── 彼此獨立隔離</span></span>
<span class="line"><span>  └─ Availability Zone（可用區，一個 Region 通常 ≥ 3 個）</span></span>
<span class="line"><span>       └─ 一或多個實體資料中心</span></span>
<span class="line"><span></span></span>
<span class="line"><span>（另外散布全球、數量最多的）</span></span>
<span class="line"><span>Edge Location ── 給 CloudFront 等做快取</span></span></code></pre></div><p>全球各地的地理區域，彼此<strong>完全獨立隔離</strong>。資料預設不會自動跨 Region 移動——這同時是合規的保障（你的資料待在你選的地方）與設計上要注意的點（跨 Region 複製要自己設定）。</p><h3 id="availability-zone-az" tabindex="-1">Availability Zone（AZ） <a class="header-anchor" href="#availability-zone-az" aria-label="Permalink to &quot;Availability Zone（AZ）&quot;">​</a></h3><p>AZ 是 Region 內一或多個實體資料中心的群組。同一 Region 的各 AZ <strong>實體隔離</strong>（不同建築、電力、網路），但彼此用低延遲高速網路相連。</p><blockquote><p>若把應用程式只放在一個 AZ，那個 AZ 斷電 / 失火，服務就全掛。<strong>跨至少兩個 AZ 部署，一個 AZ 出事時，其他 AZ 仍能服務</strong>——這就是高可用性（High Availability）的基礎。</p></blockquote><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Region（東京）</span></span>
<span class="line"><span>├─ AZ-a ── EC2</span></span>
<span class="line"><span>│           ↑ 一個 AZ 故障，其他 AZ 仍正常服務</span></span>
<span class="line"><span>├─ AZ-c ── EC2</span></span>
<span class="line"><span>│           ↑ ELB 自動把流量只導向健康的執行個體</span></span>
<span class="line"><span>└─ AZ-d ── EC2</span></span></code></pre></div><blockquote><p>💡 這就是為什麼 ELB + Auto Scaling 通常會「跨多個 AZ」配置——把機器分散到不同 AZ，才真正達到高可用性（High Availability）。</p></blockquote><h3 id="多-az-vs-多-region" tabindex="-1">多 AZ vs 多 Region <a class="header-anchor" href="#多-az-vs-多-region" aria-label="Permalink to &quot;多 AZ vs 多 Region&quot;">​</a></h3><p>這兩個常被混用，但防範的災難等級不同：</p><table tabindex="0"><thead><tr><th></th><th>多 AZ（Multi-AZ）</th><th>多 Region（Multi-Region）</th></tr></thead><tbody><tr><td><strong>目的</strong></td><td>高可用——一個 AZ 掛了，同 Region 其他 AZ 頂上</td><td>災難復原——整個 Region 失聯也能繼續服務</td></tr><tr><td><strong>範圍</strong></td><td>同一個 Region 內</td><td>跨地理區域（如 us-east-1 ＋ ap-northeast-1）</td></tr><tr><td><strong>成本</strong></td><td>較低</td><td>較高（需在多 Region 複製資源）</td></tr><tr><td><strong>典型用途</strong></td><td>一般高可用設計、資料庫備援</td><td>全球使用者、嚴格的 RTO／RPO 災難復原</td></tr></tbody></table><blockquote><p>「一個資料中心故障不能中斷」→ <strong>多 AZ</strong></p><p>「整個區域因天災失聯也要繼續服務 / 服務全球用戶」→ <strong>多 Region</strong>。</p></blockquote><h3 id="edge-location-邊緣節點" tabindex="-1">Edge Location（邊緣節點） <a class="header-anchor" href="#edge-location-邊緣節點" aria-label="Permalink to &quot;Edge Location（邊緣節點）&quot;">​</a></h3><p>散布全球、數量遠多於 Region 的據點，把內容快取在離使用者近的地方。CloudFront（CDN）就是用它：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>使用者（台北）→ 最近的 Edge Location</span></span>
<span class="line"><span>                ├─（快取命中）→ 直接回應，超快</span></span>
<span class="line"><span>                └─（快取沒有）→ 回源頭（如東京 Region 的 S3 / EC2）拿</span></span></code></pre></div><blockquote><p>💡 CloudFront 的詳細快取行為屬於網路章節內容；這裡只記「Edge Location = 離使用者最近的快取據點」。</p></blockquote><h2 id="把-aws-延伸到更靠近的地方" tabindex="-1">把 AWS 延伸到更靠近的地方 <a class="header-anchor" href="#把-aws-延伸到更靠近的地方" aria-label="Permalink to &quot;把 AWS 延伸到更靠近的地方&quot;">​</a></h2><p>當「最近的 Region」還是不夠近，或必須在自己場地時，有三個延伸選項：</p><table tabindex="0"><thead><tr><th>服務</th><th>用途</th></tr></thead><tbody><tr><td><strong>AWS Local Zones</strong></td><td>把運算 / 儲存放到更靠近大城市使用者的地方，進一步降低延遲</td></tr><tr><td><strong>AWS Wavelength</strong></td><td>把 AWS 服務嵌入電信 5G 網路邊緣，給行動裝置超低延遲</td></tr><tr><td><strong>AWS Outposts</strong></td><td>把 AWS 的硬體與服務搬進你自己的機房（地端用 AWS 的方式管理）</td></tr></tbody></table><h2 id="基礎設施自動化" tabindex="-1">基礎設施自動化 <a class="header-anchor" href="#基礎設施自動化" aria-label="Permalink to &quot;基礎設施自動化&quot;">​</a></h2><p>手動在主控台一個一個點資源，容易出錯、難以重複、也難在多個 Region 複製同一套環境。解法是<strong>基礎設施即程式碼（IaC，Infrastructure as Code）</strong>。</p><table tabindex="0"><thead><tr><th>服務</th><th>怎麼寫 IaC</th><th>重點</th></tr></thead><tbody><tr><td><strong>AWS CloudFormation</strong></td><td>YAML / JSON 範本，宣告式</td><td>AWS 原生 IaC；範本寫一次，一鍵部署整套環境</td></tr><tr><td><strong>AWS CDK</strong>（Cloud Development Kit）</td><td>Python、TypeScript 等程式語言</td><td>用熟悉的語言寫 IaC，底層自動產生 CloudFormation</td></tr></tbody></table><blockquote><p>「要可重複、一致地部署整套基礎設施」「基礎設施即程式碼」「在多個 Region 部署相同環境」→ <strong>CloudFormation</strong>。</p><p>CLF 考 CDK 時通常問「用程式語言寫 IaC 是哪個服務」→ <strong>CDK</strong>。</p></blockquote><p><strong>手動 vs IaC 對比：</strong></p><table tabindex="0"><thead><tr><th></th><th>手動建立</th><th>IaC（CloudFormation / CDK）</th></tr></thead><tbody><tr><td>流程</td><td>一個一個點，步驟靠記憶</td><td>範本 / 程式碼寫一次，一鍵部署整套</td></tr><tr><td>可重複性</td><td>難重現、容易漏設定</td><td>可重複、一致，多 Region 部署同一套</td></tr><tr><td>版本管理</td><td>沒有版本紀錄</td><td>可版本控制、可審查、可回滾</td></tr></tbody></table><h2 id="重點整理" tabindex="-1">重點整理 <a class="header-anchor" href="#重點整理" aria-label="Permalink to &quot;重點整理&quot;">​</a></h2><ul><li>走向全球的理由：降延遲、符法規、提高可靠性、擴大觸及</li><li>選 Region 四考量：<strong>法規落地 &gt; 鄰近 / 延遲 &gt; 服務可用性 &gt; 價格</strong>——法規通常最優先</li><li>Region 彼此獨立隔離、資料預設不跨 Region；AZ 是 Region 內實體隔離但低延遲相連的資料中心群</li><li><strong>多 AZ = 高可用</strong>（一個 AZ 掛了同 Region 其他頂上）</li><li><strong>多 Region = 災難復原 / 全球化</strong>（整個 Region 失聯也能服務）</li><li><strong>Edge Location</strong> = 數量最多、離使用者最近的快取據點，CloudFront 用它降延遲</li><li>邊緣延伸：<strong>Local Zones</strong>（更近大城市）、<strong>Wavelength</strong>（電信 5G 邊緣）、<strong>Outposts</strong>（地端跑 AWS）</li><li>🚨 <strong>CloudFormation</strong> = YAML/JSON 範本 IaC，可重複一致部署；<strong>CDK</strong> = 用程式語言寫 IaC（底層是 CloudFormation）</li></ul><table tabindex="0"><thead><tr><th>情境需求</th><th>答案 / 重點</th></tr></thead><tbody><tr><td>資料依法必須留在某國</td><td>選該國 Region（法規優先）</td></tr><tr><td>使用者集中某地、要最低延遲</td><td>選鄰近的 Region</td></tr><tr><td>一個資料中心故障也不能中斷服務</td><td>跨多個 AZ 部署</td></tr><tr><td>整個 Region 天災失聯也要繼續服務</td><td>多 Region 部署</td></tr><tr><td>把靜態內容放到離全球使用者最近處</td><td>Edge Location / CloudFront</td></tr><tr><td>要更靠近大城市使用者、再降延遲</td><td>Local Zones</td></tr><tr><td>行動裝置走 5G、要超低延遲</td><td>Wavelength</td></tr><tr><td>必須在自己機房用 AWS</td><td>Outposts</td></tr><tr><td>可重複、一致地部署整套基礎設施</td><td>CloudFormation（IaC）</td></tr><tr><td>用程式語言（Python / TypeScript）寫 IaC</td><td>AWS CDK</td></tr></tbody></table>`,39)])])}const b=a(r,[["render",s]]);export{c as __pageData,b as default};
